  1→// Package jira provides a JIRA REST API client for work order ticket management.
  2→// All tokens are resolved from environment variables — never stored in code or config.
  3→package jira
  4→
  5→import (
  6→	"context"
  7→	"net/http"
  8→	"time"
  9→)
 10→
 11→// Issue represents a JIRA issue summary.
 12→type Issue struct {
 13→	Key         string   `json:"key"`
 14→	Summary     string   `json:"summary"`
 15→	Description string   `json:"description"`
 16→	Status      string   `json:"status"`
 17→	Priority    string   `json:"priority"`
 18→	Assignee    string   `json:"assignee,omitempty"`
 19→	Labels      []string `json:"labels,omitempty"`
 20→	WOID        string   `json:"wo_id,omitempty"` // chainwatch WO ID stored as label
 21→}
 22→
 23→// CreateIssueInput describes a new JIRA issue to create.
 24→type CreateIssueInput struct {
 25→	Summary     string
 26→	Description string
 27→	Priority    string // JIRA priority name (e.g. "Highest", "High")
 28→	Assignee    string
 29→	Labels      []string
 30→	WOID        string // added as label: "wo:<id>"
 31→}
 32→
 33→// Transition describes a JIRA issue status transition.
 34→type Transition struct {
 35→	ID   string `json:"id"`
 36→	Name string `json:"name"`
 37→}
 38→
 39→// Creator is the interface the orchestrator dispatch uses to create JIRA tickets.
 40→type Creator interface {
 41→	CreateIssue(ctx context.Context, input CreateIssueInput) (*Issue, error)
 42→	AddComment(ctx context.Context, issueKey, body string) error
 43→}
 44→
 45→// Closer is the interface the orchestrator verify uses to close JIRA tickets.
 46→type Closer interface {
 47→	TransitionIssue(ctx context.Context, issueKey, targetStatus string) error
 48→}
 49→
 50→// Client is a JIRA REST API client.
 51→type Client struct {
 52→	baseURL    string
 53→	token      string
 54→	project    string
 55→	assignee   string
 56→	httpClient *http.Client
 57→}
 58→
 59→// ClientConfig holds construction parameters for a JIRA client.
 60→type ClientConfig struct {
 61→	BaseURL  string
 62→	Token    string
 63→	Project  string
 64→	Assignee string
 65→	Client   *http.Client // nil uses http.DefaultClient
 66→}
 67→
 68→// NewClient creates a JIRA REST API client.
 69→func NewClient(cfg ClientConfig) *Client {
 70→	hc := cfg.Client
 71→	if hc == nil {
 72→		hc = &http.Client{Timeout: 30 * time.Second}
 73→	}
 74→	return &Client{
 75→		baseURL:    cfg.BaseURL,
 76→		token:      cfg.Token,
 77→		project:    cfg.Project,
 78→		assignee:   cfg.Assignee,
 79→		httpClient: hc,
 80→	}
 81→}
 82→
 83→// CreateIssue creates a JIRA issue via REST API.
 84→// Implementation provided in client.go.
 85→func (c *Client) CreateIssue(ctx context.Context, input CreateIssueInput) (*Issue, error) {
 86→	return createIssue(c, ctx, input)
 87→}
 88→
 89→// GetIssue retrieves a JIRA issue by key.
 90→func (c *Client) GetIssue(ctx context.Context, issueKey string) (*Issue, error) {
 91→	return getIssue(c, ctx, issueKey)
 92→}
 93→
 94→// AddComment adds a comment to a JIRA issue.
 95→func (c *Client) AddComment(ctx context.Context, issueKey, body string) error {
 96→	return addComment(c, ctx, issueKey, body)
 97→}
 98→
 99→// TransitionIssue transitions a JIRA issue to the target status.
100→func (c *Client) TransitionIssue(ctx context.Context, issueKey, targetStatus string) error {
101→	return transitionIssue(c, ctx, issueKey, targetStatus)
102→}
103→
104→// MapPriority converts a chainwatch severity to a JIRA priority name
105→// using the provided priority map from inventory config.
106→func MapPriority(severity string, priorityMap map[string]string) string {
107→	if p, ok := priorityMap[severity]; ok {
108→		return p
109→	}
110→	// Sensible defaults.
111→	defaults := map[string]string{
112→		"critical": "Highest",
113→		"high":     "High",
114→		"medium":   "Medium",
115→		"low":      "Low",
116→	}
117→	if p, ok := defaults[severity]; ok {
118→		return p
119→	}
120→	return "Medium"
121→}
122→

  1→package jira
  2→
  3→import (
  4→	"bytes"
  5→	"context"
  6→	"encoding/json"
  7→	"fmt"
  8→	"io"
  9→	"net/http"
 10→	"strings"
 11→)
 12→
 13→// createIssue performs the JIRA REST API call to create an issue.
 14→func createIssue(c *Client, ctx context.Context, input CreateIssueInput) (*Issue, error) {
 15→	labels := make([]string, 0, len(input.Labels)+2)
 16→	labels = append(labels, "nullbot", "automated")
 17→	labels = append(labels, input.Labels...)
 18→	if input.WOID != "" {
 19→		labels = append(labels, "wo:"+input.WOID)
 20→	}
 21→
 22→	body := map[string]any{
 23→		"fields": map[string]any{
 24→			"project":     map[string]string{"key": c.project},
 25→			"issuetype":   map[string]string{"name": "Task"},
 26→			"summary":     input.Summary,
 27→			"description": input.Description,
 28→			"priority":    map[string]string{"name": input.Priority},
 29→			"labels":      labels,
 30→		},
 31→	}
 32→
 33→	if input.Assignee != "" {
 34→		body["fields"].(map[string]any)["assignee"] = map[string]string{"name": input.Assignee}
 35→	} else if c.assignee != "" {
 36→		body["fields"].(map[string]any)["assignee"] = map[string]string{"name": c.assignee}
 37→	}
 38→
 39→	data, err := json.Marshal(body)
 40→	if err != nil {
 41→		return nil, fmt.Errorf("marshal create issue body: %w", err)
 42→	}
 43→
 44→	resp, err := c.doRequest(ctx, http.MethodPost, "/rest/api/2/issue", data)
 45→	if err != nil {
 46→		return nil, fmt.Errorf("create issue request: %w", err)
 47→	}
 48→	defer resp.Body.Close()
 49→
 50→	if resp.StatusCode != http.StatusCreated {
 51→		return nil, readError(resp)
 52→	}
 53→
 54→	var result struct {
 55→		Key string `json:"key"`
 56→	}
 57→	if err := json.NewDecoder(resp.Body).Decode(&result); err != nil {
 58→		return nil, fmt.Errorf("decode create issue response: %w", err)
 59→	}
 60→
 61→	return &Issue{
 62→		Key:         result.Key,
 63→		Summary:     input.Summary,
 64→		Description: input.Description,
 65→		Priority:    input.Priority,
 66→		Labels:      labels,
 67→		WOID:        input.WOID,
 68→	}, nil
 69→}
 70→
 71→// getIssue retrieves a JIRA issue by key.
 72→func getIssue(c *Client, ctx context.Context, issueKey string) (*Issue, error) {
 73→	resp, err := c.doRequest(ctx, http.MethodGet, "/rest/api/2/issue/"+issueKey, nil)
 74→	if err != nil {
 75→		return nil, fmt.Errorf("get issue request: %w", err)
 76→	}
 77→	defer resp.Body.Close()
 78→
 79→	if resp.StatusCode != http.StatusOK {
 80→		return nil, readError(resp)
 81→	}
 82→
 83→	var raw struct {
 84→		Key    string `json:"key"`
 85→		Fields struct {
 86→			Summary     string `json:"summary"`
 87→			Description string `json:"description"`
 88→			Status      struct {
 89→				Name string `json:"name"`
 90→			} `json:"status"`
 91→			Priority struct {
 92→				Name string `json:"name"`
 93→			} `json:"priority"`
 94→			Assignee *struct {
 95→				Name string `json:"name"`
 96→			} `json:"assignee"`
 97→			Labels []string `json:"labels"`
 98→		} `json:"fields"`
 99→	}
100→	if err := json.NewDecoder(resp.Body).Decode(&raw); err != nil {
101→		return nil, fmt.Errorf("decode get issue response: %w", err)
102→	}
103→
104→	issue := &Issue{
105→		Key:         raw.Key,
106→		Summary:     raw.Fields.Summary,
107→		Description: raw.Fields.Description,
108→		Status:      raw.Fields.Status.Name,
109→		Priority:    raw.Fields.Priority.Name,
110→		Labels:      raw.Fields.Labels,
111→	}
112→	if raw.Fields.Assignee != nil {
113→		issue.Assignee = raw.Fields.Assignee.Name
114→	}
115→	// Extract WO ID from labels.
116→	for _, l := range raw.Fields.Labels {
117→		if strings.HasPrefix(l, "wo:") {
118→			issue.WOID = strings.TrimPrefix(l, "wo:")
119→			break
120→		}
121→	}
122→	return issue, nil
123→}
124→
125→// addComment adds a comment to a JIRA issue.
126→func addComment(c *Client, ctx context.Context, issueKey, body string) error {
127→	data, err := json.Marshal(map[string]string{"body": body})
128→	if err != nil {
129→		return fmt.Errorf("marshal comment body: %w", err)
130→	}
131→
132→	resp, err := c.doRequest(ctx, http.MethodPost, "/rest/api/2/issue/"+issueKey+"/comment", data)
133→	if err != nil {
134→		return fmt.Errorf("add comment request: %w", err)
135→	}
136→	defer resp.Body.Close()
137→
138→	if resp.StatusCode != http.StatusCreated {
139→		return readError(resp)
140→	}
141→	return nil
142→}
143→
144→// transitionIssue transitions a JIRA issue to the target status name.
145→func transitionIssue(c *Client, ctx context.Context, issueKey, targetStatus string) error {
146→	// First, get available transitions.
147→	resp, err := c.doRequest(ctx, http.MethodGet, "/rest/api/2/issue/"+issueKey+"/transitions", nil)
148→	if err != nil {
149→		return fmt.Errorf("get transitions request: %w", err)
150→	}
151→	defer resp.Body.Close()
152→
153→	if resp.StatusCode != http.StatusOK {
154→		return readError(resp)
155→	}
156→
157→	var transitions struct {
158→		Transitions []struct {
159→			ID   string `json:"id"`
160→			Name string `json:"name"`
161→			To   struct {
162→				Name string `json:"name"`
163→			} `json:"to"`
164→		} `json:"transitions"`
165→	}
166→	if err := json.NewDecoder(resp.Body).Decode(&transitions); err != nil {
167→		return fmt.Errorf("decode transitions: %w", err)
168→	}
169→
170→	// Find matching transition.
171→	target := strings.ToLower(targetStatus)
172→	for _, t := range transitions.Transitions {
173→		if strings.ToLower(t.To.Name) == target || strings.ToLower(t.Name) == target {
174→			data, err := json.Marshal(map[string]any{
175→				"transition": map[string]string{"id": t.ID},
176→			})
177→			if err != nil {
178→				return fmt.Errorf("marshal transition body: %w", err)
179→			}
180→
181→			resp2, err := c.doRequest(ctx, http.MethodPost, "/rest/api/2/issue/"+issueKey+"/transitions", data)
182→			if err != nil {
183→				return fmt.Errorf("transition request: %w", err)
184→			}
185→			defer resp2.Body.Close()
186→
187→			if resp2.StatusCode != http.StatusNoContent && resp2.StatusCode != http.StatusOK {
188→				return readError(resp2)
189→			}
190→			return nil
191→		}
192→	}
193→
194→	available := make([]string, 0, len(transitions.Transitions))
195→	for _, t := range transitions.Transitions {
196→		available = append(available, t.To.Name)
197→	}
198→	return fmt.Errorf("no transition to %q found for %s (available: %s)", targetStatus, issueKey, strings.Join(available, ", "))
199→}
200→
201→// doRequest performs an authenticated HTTP request to the JIRA API.
202→func (c *Client) doRequest(ctx context.Context, method, path string, body []byte) (*http.Response, error) {
203→	url := strings.TrimRight(c.baseURL, "/") + path
204→
205→	var bodyReader io.Reader
206→	if body != nil {
207→		bodyReader = bytes.NewReader(body)
208→	}
209→
210→	req, err := http.NewRequestWithContext(ctx, method, url, bodyReader)
211→	if err != nil {
212→		return nil, err
213→	}
214→	req.Header.Set("Authorization", "Bearer "+c.token)
215→	req.Header.Set("Content-Type", "application/json")
216→	req.Header.Set("Accept", "application/json")
217→
218→	return c.httpClient.Do(req)
219→}
220→
221→// readError extracts an error message from a non-success HTTP response.
222→func readError(resp *http.Response) error {
223→	body, _ := io.ReadAll(io.LimitReader(resp.Body, 4096))
224→	return fmt.Errorf("JIRA API %s %s: %d %s", resp.Request.Method, resp.Request.URL.Path, resp.StatusCode, string(body))
225→}
