  1→package observe
  2→
  3→import (
  4→	"database/sql"
  5→	"encoding/json"
  6→	"fmt"
  7→	"os"
  8→	"path/filepath"
  9→	"strings"
 10→	"time"
 11→
 12→	_ "modernc.org/sqlite"
 13→)
 14→
 15→// CachedObservation holds raw evidence when LLM classification is unavailable.
 16→// Written to state/cache.db by the daemon processor, retried by the cache sweeper.
 17→type CachedObservation struct {
 18→	ID          string    `json:"id"`
 19→	JobID       string    `json:"job_id"`
 20→	Scope       string    `json:"scope"`
 21→	Type        string    `json:"type"`
 22→	Sensitivity string    `json:"sensitivity,omitempty"`
 23→	Evidence    string    `json:"evidence"`
 24→	CachedAt    time.Time `json:"cached_at"`
 25→	RetryCount  int       `json:"retry_count"`
 26→}
 27→
 28→const (
 29→	cacheDBName      = "cache.db"
 30→	legacyCacheDir   = "cache"
 31→	cacheParentPerm  = 0750
 32→	sqliteBusyMillis = 5000
 33→)
 34→
 35→// CacheDir returns the standard cache database path within a state dir.
 36→func CacheDir(stateDir string) string {
 37→	return filepath.Join(stateDir, cacheDBName)
 38→}
 39→
 40→// WriteCache persists a raw observation to the cache database.
 41→func WriteCache(cachePath string, entry *CachedObservation) error {
 42→	if entry == nil {
 43→		return fmt.Errorf("cache entry is nil")
 44→	}
 45→	if strings.TrimSpace(entry.ID) == "" {
 46→		return fmt.Errorf("cache entry id is required")
 47→	}
 48→	db, err := openCacheDB(cachePath, true)
 49→	if err != nil {
 50→		return err
 51→	}
 52→	defer func() {
 53→		_ = db.Close()
 54→	}()
 55→
 56→	return upsertObservation(db, entry)
 57→}
 58→
 59→// ReadCache reads all cached observations from the cache database.
 60→// Returns nil (not error) if the database and legacy cache dir do not exist.
 61→func ReadCache(cachePath string) ([]*CachedObservation, error) {
 62→	db, err := openCacheDB(cachePath, false)
 63→	if err != nil {
 64→		return nil, err
 65→	}
 66→	if db == nil {
 67→		return nil, nil
 68→	}
 69→	defer func() {
 70→		_ = db.Close()
 71→	}()
 72→
 73→	rows, err := db.Query(`
 74→		SELECT id, job_id, scope, type, sensitivity, evidence, cached_at, retry_count
 75→		FROM observations
 76→		ORDER BY cached_at ASC, id ASC
 77→	`)
 78→	if err != nil {
 79→		return nil, fmt.Errorf("query cache: %w", err)
 80→	}
 81→	defer func() {
 82→		_ = rows.Close()
 83→	}()
 84→
 85→	return scanObservations(rows)
 86→}
 87→
 88→// SearchCache returns cached observations where evidence matches an FTS5 query.
 89→func SearchCache(cachePath, query string) ([]*CachedObservation, error) {
 90→	trimmed := strings.TrimSpace(query)
 91→	if trimmed == "" {
 92→		return ReadCache(cachePath)
 93→	}
 94→
 95→	db, err := openCacheDB(cachePath, false)
 96→	if err != nil {
 97→		return nil, err
 98→	}
 99→	if db == nil {
100→		return nil, nil
101→	}
102→	defer func() {
103→		_ = db.Close()
104→	}()
105→
106→	result, err := queryFTS(db, trimmed)
107→	if err == nil {
108→		return result, nil
109→	}
110→
111→	quoted := quoteFTSQuery(trimmed)
112→	if quoted == trimmed {
113→		return nil, err
114→	}
115→	return queryFTS(db, quoted)
116→}
117→
118→// ListByType returns cached observations filtered by observation type.
119→func ListByType(cachePath, obsType string) ([]*CachedObservation, error) {
120→	trimmed := strings.TrimSpace(obsType)
121→	if trimmed == "" {
122→		return ReadCache(cachePath)
123→	}
124→
125→	db, err := openCacheDB(cachePath, false)
126→	if err != nil {
127→		return nil, err
128→	}
129→	if db == nil {
130→		return nil, nil
131→	}
132→	defer func() {
133→		_ = db.Close()
134→	}()
135→
136→	rows, err := db.Query(`
137→		SELECT id, job_id, scope, type, sensitivity, evidence, cached_at, retry_count
138→		FROM observations
139→		WHERE type = ?
140→		ORDER BY cached_at DESC, id ASC
141→	`, trimmed)
142→	if err != nil {
143→		return nil, fmt.Errorf("list cache by type: %w", err)
144→	}
145→	defer func() {
146→		_ = rows.Close()
147→	}()
148→
149→	return scanObservations(rows)
150→}
151→
152→// ListRecent returns cached observations at or after the supplied timestamp.
153→func ListRecent(cachePath string, since time.Time) ([]*CachedObservation, error) {
154→	db, err := openCacheDB(cachePath, false)
155→	if err != nil {
156→		return nil, err
157→	}
158→	if db == nil {
159→		return nil, nil
160→	}
161→	defer func() {
162→		_ = db.Close()
163→	}()
164→
165→	rows, err := db.Query(`
166→		SELECT id, job_id, scope, type, sensitivity, evidence, cached_at, retry_count
167→		FROM observations
168→		WHERE cached_at >= ?
169→		ORDER BY cached_at DESC, id ASC
170→	`, since.UTC().UnixNano())
171→	if err != nil {
172→		return nil, fmt.Errorf("list recent cache: %w", err)
173→	}
174→	defer func() {
175→		_ = rows.Close()
176→	}()
177→
178→	return scanObservations(rows)
179→}
180→
181→// RemoveCached removes a processed cache entry.
182→func RemoveCached(cachePath, id string) error {
183→	db, err := openCacheDB(cachePath, true)
184→	if err != nil {
185→		return err
186→	}
187→	defer func() {
188→		_ = db.Close()
189→	}()
190→
191→	if _, err := db.Exec(`DELETE FROM observations WHERE id = ?`, id); err != nil {
192→		return fmt.Errorf("delete cache entry %q: %w", id, err)
193→	}
194→	return nil
195→}
196→
197→func openCacheDB(cachePath string, create bool) (*sql.DB, error) {
198→	dbPath, legacyDirPath := resolveCachePaths(cachePath)
199→	if !create {
200→		dbExists, err := fileExists(dbPath)
201→		if err != nil {
202→			return nil, fmt.Errorf("stat cache db: %w", err)
203→		}
204→		legacyExists, err := dirExists(legacyDirPath)
205→		if err != nil {
206→			return nil, fmt.Errorf("stat legacy cache dir: %w", err)
207→		}
208→		if !dbExists && !legacyExists {
209→			return nil, nil
210→		}
211→	}
212→
213→	if err := os.MkdirAll(filepath.Dir(dbPath), cacheParentPerm); err != nil {
214→		return nil, fmt.Errorf("create cache db parent: %w", err)
215→	}
216→
217→	db, err := sql.Open("sqlite", dbPath)
218→	if err != nil {
219→		return nil, fmt.Errorf("open cache db: %w", err)
220→	}
221→	db.SetMaxOpenConns(1)
222→	db.SetMaxIdleConns(1)
223→
224→	if err := configureSQLite(db); err != nil {
225→		_ = db.Close()
226→		return nil, err
227→	}
228→	if err := ensureSchema(db); err != nil {
229→		_ = db.Close()
230→		return nil, err
231→	}
232→	if err := migrateLegacyCache(db, legacyDirPath); err != nil {
233→		_ = db.Close()
234→		return nil, err
235→	}
236→	return db, nil
237→}
238→
239→func resolveCachePaths(cachePath string) (dbPath string, legacyDirPath string) {
240→	cleanPath := filepath.Clean(cachePath)
241→	if strings.EqualFold(filepath.Ext(cleanPath), ".db") {
242→		return cleanPath, filepath.Join(filepath.Dir(cleanPath), legacyCacheDir)
243→	}
244→	return filepath.Join(filepath.Dir(cleanPath), cacheDBName), cleanPath
245→}
246→
247→func configureSQLite(db *sql.DB) error {
248→	pragmas := []string{
249→		fmt.Sprintf("PRAGMA busy_timeout = %d", sqliteBusyMillis),
250→		"PRAGMA synchronous = NORMAL",
251→	}
252→	for _, pragma := range pragmas {
253→		if _, err := db.Exec(pragma); err != nil {
254→			return fmt.Errorf("configure sqlite %q: %w", pragma, err)
255→		}
256→	}
257→
258→	// journal_mode can briefly contend when many writers open the DB at once.
259→	// If another writer already flipped the DB into WAL mode, SQLITE_BUSY here
260→	// is safe to ignore.
261→	if _, err := db.Exec("PRAGMA journal_mode = WAL"); err != nil {
262→		if !strings.Contains(err.Error(), "SQLITE_BUSY") {
263→			return fmt.Errorf("configure sqlite %q: %w", "PRAGMA journal_mode = WAL", err)
264→		}
265→	}
266→	return nil
267→}
268→
269→func ensureSchema(db *sql.DB) error {
270→	stmts := []string{
271→		`CREATE TABLE IF NOT EXISTS observations (
272→			id TEXT PRIMARY KEY,
273→			job_id TEXT NOT NULL DEFAULT '',
274→			scope TEXT NOT NULL DEFAULT '',
275→			type TEXT NOT NULL DEFAULT '',
276→			sensitivity TEXT,
277→			evidence TEXT NOT NULL DEFAULT '',
278→			cached_at INTEGER NOT NULL,
279→			retry_count INTEGER NOT NULL DEFAULT 0
280→		)`,
281→		`CREATE INDEX IF NOT EXISTS idx_observations_type ON observations(type)`,
282→		`CREATE INDEX IF NOT EXISTS idx_observations_cached_at ON observations(cached_at DESC)`,
283→		`CREATE TABLE IF NOT EXISTS finding_hashes (
284→			hash TEXT PRIMARY KEY,
285→			first_seen INTEGER NOT NULL,
286→			last_seen INTEGER NOT NULL,
287→			wo_id TEXT NOT NULL DEFAULT '',
288→			status TEXT NOT NULL DEFAULT 'open'
289→		)`,
290→		`CREATE INDEX IF NOT EXISTS idx_finding_hashes_status ON finding_hashes(status)`,
291→		`CREATE INDEX IF NOT EXISTS idx_finding_hashes_last_seen ON finding_hashes(last_seen DESC)`,
292→		`CREATE VIRTUAL TABLE IF NOT EXISTS observations_fts USING fts5(
293→			evidence,
294→			content='observations',
295→			content_rowid='rowid'
296→		)`,
297→		`CREATE TRIGGER IF NOT EXISTS observations_ai AFTER INSERT ON observations BEGIN
298→			INSERT INTO observations_fts(rowid, evidence) VALUES (new.rowid, new.evidence);
299→		END`,
300→		`CREATE TRIGGER IF NOT EXISTS observations_ad AFTER DELETE ON observations BEGIN
301→			INSERT INTO observations_fts(observations_fts, rowid, evidence)
302→			VALUES ('delete', old.rowid, old.evidence);
303→		END`,
304→		`CREATE TRIGGER IF NOT EXISTS observations_au AFTER UPDATE ON observations BEGIN
305→			INSERT INTO observations_fts(observations_fts, rowid, evidence)
306→			VALUES ('delete', old.rowid, old.evidence);
307→			INSERT INTO observations_fts(rowid, evidence) VALUES (new.rowid, new.evidence);
308→		END`,
309→	}
310→
311→	for _, stmt := range stmts {
312→		if _, err := db.Exec(stmt); err != nil {
313→			return fmt.Errorf("create cache schema: %w", err)
314→		}
315→	}
316→
317→	var observationCount int
318→	if err := db.QueryRow(`SELECT COUNT(1) FROM observations`).Scan(&observationCount); err != nil {
319→		return fmt.Errorf("count observations: %w", err)
320→	}
321→	if observationCount == 0 {
322→		return nil
323→	}
324→
325→	var ftsCount int
326→	if err := db.QueryRow(`SELECT COUNT(1) FROM observations_fts`).Scan(&ftsCount); err != nil {
327→		return fmt.Errorf("count fts rows: %w", err)
328→	}
329→	if ftsCount > 0 {
330→		return nil
331→	}
332→
333→	if _, err := db.Exec(`INSERT INTO observations_fts(observations_fts) VALUES ('rebuild')`); err != nil {
334→		return fmt.Errorf("rebuild fts index: %w", err)
335→	}
336→	return nil
337→}
338→
339→func migrateLegacyCache(db *sql.DB, legacyDirPath string) error {
340→	entries, err := os.ReadDir(legacyDirPath)
341→	if err != nil {
342→		if os.IsNotExist(err) {
343→			return nil
344→		}
345→		return fmt.Errorf("read legacy cache dir: %w", err)
346→	}
347→
348→	tx, err := db.Begin()
349→	if err != nil {
350→		return fmt.Errorf("begin legacy cache migration: %w", err)
351→	}
352→	committed := false
353→	defer func() {
354→		if !committed {
355→			_ = tx.Rollback()
356→		}
357→	}()
358→
359→	migratedFiles := make([]string, 0, len(entries))
360→	for _, e := range entries {
361→		if e.IsDir() {
362→			continue
363→		}
364→		name := e.Name()
365→		if !strings.HasSuffix(name, ".json") || strings.HasSuffix(name, ".tmp") {
366→			continue
367→		}
368→
369→		path := filepath.Join(legacyDirPath, name)
370→		data, err := os.ReadFile(path)
371→		if err != nil {
372→			continue
373→		}
374→
375→		var entry CachedObservation
376→		if err := json.Unmarshal(data, &entry); err != nil {
377→			continue
378→		}
379→		if strings.TrimSpace(entry.ID) == "" {
380→			continue
381→		}
382→
383→		if err := upsertObservation(tx, &entry); err != nil {
384→			return fmt.Errorf("migrate cache entry %s: %w", path, err)
385→		}
386→		migratedFiles = append(migratedFiles, path)
387→	}
388→
389→	if err := tx.Commit(); err != nil {
390→		return fmt.Errorf("commit legacy cache migration: %w", err)
391→	}
392→	committed = true
393→
394→	for _, path := range migratedFiles {
395→		_ = os.Remove(path)
396→	}
397→	_ = os.Remove(legacyDirPath)
398→
399→	return nil
400→}
401→
402→type sqlExecer interface {
403→	Exec(query string, args ...any) (sql.Result, error)
404→}
405→
406→func upsertObservation(execer sqlExecer, entry *CachedObservation) error {
407→	if strings.TrimSpace(entry.ID) == "" {
408→		return fmt.Errorf("cache entry id is required")
409→	}
410→	if entry.JobID == "" {
411→		entry.JobID = entry.ID
412→	}
413→	if entry.CachedAt.IsZero() {
414→		entry.CachedAt = time.Now().UTC()
415→	}
416→
417→	_, err := execer.Exec(`
418→		INSERT INTO observations (
419→			id, job_id, scope, type, sensitivity, evidence, cached_at, retry_count
420→		) VALUES (?, ?, ?, ?, ?, ?, ?, ?)
421→		ON CONFLICT(id) DO UPDATE SET
422→			job_id = excluded.job_id,
423→			scope = excluded.scope,
424→			type = excluded.type,
425→			sensitivity = excluded.sensitivity,
426→			evidence = excluded.evidence,
427→			cached_at = excluded.cached_at,
428→			retry_count = excluded.retry_count
429→	`,
430→		entry.ID,
431→		entry.JobID,
432→		entry.Scope,
433→		entry.Type,
434→		entry.Sensitivity,
435→		entry.Evidence,
436→		entry.CachedAt.UTC().UnixNano(),
437→		entry.RetryCount,
438→	)
439→	if err != nil {
440→		return fmt.Errorf("upsert cache entry %q: %w", entry.ID, err)
441→	}
442→	return nil
443→}
444→
445→func queryFTS(db *sql.DB, query string) ([]*CachedObservation, error) {
446→	rows, err := db.Query(`
447→		SELECT o.id, o.job_id, o.scope, o.type, o.sensitivity, o.evidence, o.cached_at, o.retry_count
448→		FROM observations o
449→		JOIN observations_fts ON observations_fts.rowid = o.rowid
450→		WHERE observations_fts MATCH ?
451→		ORDER BY bm25(observations_fts), o.cached_at DESC, o.id ASC
452→	`, query)
453→	if err != nil {
454→		return nil, fmt.Errorf("search cache: %w", err)
455→	}
456→	defer func() {
457→		_ = rows.Close()
458→	}()
459→	return scanObservations(rows)
460→}
461→
462→func quoteFTSQuery(query string) string {
463→	if strings.HasPrefix(query, "\"") && strings.HasSuffix(query, "\"") {
464→		return query
465→	}
466→	escaped := strings.ReplaceAll(query, "\"", "\"\"")
467→	return `"` + escaped + `"`
468→}
469→
470→func scanObservations(rows *sql.Rows) ([]*CachedObservation, error) {
471→	var cached []*CachedObservation
472→	for rows.Next() {
473→		var (
474→			entry       CachedObservation
475→			sensitivity sql.NullString
476→			cachedAt    int64
477→		)
478→
479→		if err := rows.Scan(
480→			&entry.ID,
481→			&entry.JobID,
482→			&entry.Scope,
483→			&entry.Type,
484→			&sensitivity,
485→			&entry.Evidence,
486→			&cachedAt,
487→			&entry.RetryCount,
488→		); err != nil {
489→			return nil, fmt.Errorf("scan cache row: %w", err)
490→		}
491→		if sensitivity.Valid {
492→			entry.Sensitivity = sensitivity.String
493→		}
494→		entry.CachedAt = time.Unix(0, cachedAt).UTC()
495→		cached = append(cached, &entry)
496→	}
497→	if err := rows.Err(); err != nil {
498→		return nil, fmt.Errorf("iterate cache rows: %w", err)
499→	}
500→	return cached, nil
501→}
