118→// Load reads, applies defaults and environment overrides, and validates inventory.
119→func Load(path string) (*Inventory, error) {
120→	if strings.TrimSpace(path) == "" {
121→		return nil, fmt.Errorf("inventory path is required")
122→	}
123→
124→	absPath, err := filepath.Abs(path)
125→	if err != nil {
126→		return nil, fmt.Errorf("resolve inventory path %q: %w", path, err)
127→	}
128→
129→	data, err := os.ReadFile(absPath)
130→	if err != nil {
131→		return nil, fmt.Errorf("read inventory %q: %w", absPath, err)
132→	}
133→
134→	inv, err := Parse(data, filepath.Dir(absPath))
135→	if err != nil {
136→		return nil, err
137→	}
138→	inv.path = absPath
139→	return inv, nil
140→}
141→
142→// Parse parses inventory from YAML bytes with a known source directory.
143→func Parse(data []byte, sourceDir string) (*Inventory, error) {
144→	var inv Inventory
145→	decoder := yaml.NewDecoder(bytes.NewReader(data))
146→	decoder.KnownFields(true)
147→	if err := decoder.Decode(&inv); err != nil {
148→		return nil, fmt.Errorf("parse inventory YAML: %w", err)
149→	}
150→
151→	baseDir := sourceDir
152→	if strings.TrimSpace(baseDir) == "" {
153→		baseDir = "."
154→	}
155→	absBaseDir, err := filepath.Abs(baseDir)
156→	if err != nil {
157→		return nil, fmt.Errorf("resolve inventory base directory %q: %w", baseDir, err)
158→	}
159→
160→	inv.dir = absBaseDir
161→	inv.applyDefaults()
162→	inv.applyEnvOverrides()
163→	inv.attachClusterBaseDir()
164→
165→	if err := inv.Validate(); err != nil {
166→		return nil, err
167→	}
168→
169→	return &inv, nil
170→}
171→
172→// Validate validates inventory invariants.
173→func (inv *Inventory) Validate() error {
174→	clusters := inv.ClickHouse.ClusterEntries
175→	if len(clusters) == 0 {
176→		return fmt.Errorf("inventory clickhouse.clusters must contain at least one cluster")
177→	}
178→
179→	seenNames := make(map[string]struct{}, len(clusters))
180→	for i, cluster := range clusters {
181→		if strings.TrimSpace(cluster.Name) == "" {
182→			return fmt.Errorf("inventory clickhouse.clusters[%d].name is required", i)
183→		}
184→		if _, ok := seenNames[cluster.Name]; ok {
185→			return fmt.Errorf("duplicate cluster name %q", cluster.Name)
186→		}
187→		seenNames[cluster.Name] = struct{}{}
188→
189→		if len(cluster.HostEntries) == 0 {
190→			return fmt.Errorf("cluster %q must have at least one host", cluster.Name)
191→		}
192→
193→		seenHosts := make(map[string]struct{}, len(cluster.HostEntries))
194→		for hostIndex, host := range cluster.HostEntries {
195→			trimmed := strings.TrimSpace(host)
196→			if trimmed == "" {
197→				return fmt.Errorf("cluster %q hosts[%d] is empty", cluster.Name, hostIndex)
198→			}
199→			if _, ok := seenHosts[trimmed]; ok {
200→				return fmt.Errorf("cluster %q has duplicate host %q", cluster.Name, trimmed)
201→			}
202→			seenHosts[trimmed] = struct{}{}
203→		}
204→
205→		if strings.TrimSpace(cluster.ConfigRepo) == "" {
206→			return fmt.Errorf("cluster %q config_repo is required", cluster.Name)
207→		}
208→
209→		if cluster.ClickHousePort < 1 || cluster.ClickHousePort > 65535 {
210→			return fmt.Errorf(
211→				"cluster %q clickhouse_port must be between 1 and 65535, got %d",
212→				cluster.Name,
213→				cluster.ClickHousePort,
214→			)
215→		}
216→	}
217→
218→	if strings.TrimSpace(inv.Bedrock.Region) == "" {
219→		return fmt.Errorf("bedrock.region is required")
220→	}
221→
222→	if inv.Orchestrator.JIRA.BaseURL != "" {
223→		parsed, err := url.ParseRequestURI(inv.Orchestrator.JIRA.BaseURL)
224→		if err != nil {
225→			return fmt.Errorf("orchestrator.jira.base_url is invalid: %w", err)
226→		}
227→		if parsed.Scheme != "https" && parsed.Scheme != "http" {
228→			return fmt.Errorf(
229→				"orchestrator.jira.base_url must use http or https, got %q",
230→				parsed.Scheme,
231→			)
232→		}
233→	}
234→
235→	if strings.TrimSpace(inv.Notifications.Slack.WebhookEnv) == "" {
236→		return fmt.Errorf("notifications.slack.webhook_env is required")
237→	}
238→	if !isValidEnvVarName(inv.Notifications.Slack.WebhookEnv) {
239→		return fmt.Errorf(
240→			"notifications.slack.webhook_env must be a valid environment variable name, got %q",
241→			inv.Notifications.Slack.WebhookEnv,
242→		)
243→	}
244→	if strings.TrimSpace(inv.Notifications.Slack.Channel) == "" {
245→		return fmt.Errorf("notifications.slack.channel is required")
246→	}
247→	if strings.TrimSpace(inv.Notifications.Slack.CriticalChannel) == "" {
248→		return fmt.Errorf("notifications.slack.critical_channel is required")
249→	}
250→	if inv.Notifications.Slack.StalePRHours < 1 {
251→		return fmt.Errorf(
252→			"notifications.slack.stale_pr_hours must be >= 1, got %d",
253→			inv.Notifications.Slack.StalePRHours,
254→		)
255→	}
256→
257→	return nil
258→}
