331→	}
332→
333→	if inv.Notifications.Slack.WebhookEnv == "" {
334→		inv.Notifications.Slack.WebhookEnv = defaultSlackWebhookEnv
335→	}
336→	if inv.Notifications.Slack.Channel == "" {
337→		inv.Notifications.Slack.Channel = defaultSlackChannel
338→	}
339→	if inv.Notifications.Slack.CriticalChannel == "" {
340→		inv.Notifications.Slack.CriticalChannel = defaultCriticalChannel
341→	}
