373→func resolveJIRAToken(cfg JIRAConfig) string {
374→	candidates := []string{
375→		os.Getenv(envJIRAToken),
376→	}
377→	if cfg.TokenEnv != "" {
378→		candidates = append(candidates, os.Getenv(cfg.TokenEnv))
379→	}
380→	if cfg.TokenEnv != defaultJIRATokenEnv {
381→		candidates = append(candidates, os.Getenv(defaultJIRATokenEnv))
382→	}
383→	candidates = append(candidates, cfg.Token)
384→
385→	for _, candidate := range candidates {
386→		token := strings.TrimSpace(candidate)
387→		if token != "" {
388→			return token
389→		}
390→	}
391→	return ""
392→}
393→
394→func isValidEnvVarName(name string) bool {
395→	if name == "" {
396→		return false
397→	}
398→
399→	for i := 0; i < len(name); i++ {
400→		c := name[i]
401→		if c == '_' || (c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') {
402→			continue
403→		}
404→		if i > 0 && c >= '0' && c <= '9' {
405→			continue
406→		}
407→		return false
408→	}
409→	return true
410→}
