 14→
 15→// Finding is a normalized observation ready for aggregation.
 16→type Finding struct {
 17→	Type     string
 18→	Severity string
 19→	Detail   string
 20→	Hash     string
 21→}
 22→
 23→// AggregateResult is the rolled-up view across all observed clusters.
 24→type AggregateResult struct {
 25→	Clusters      []ClusterSummary
 26→	CrossCluster  []ConsolidatedFinding
 27→	TotalFindings int
 28→	BySeverity    map[string]int
 29→	ByType        map[string]int
 30→}
 31→
 32→// ClusterSummary captures cluster-level health counts.
 33→type ClusterSummary struct {
 34→	Name         string
 35→	HostCount    int
 36→	FindingCount int
 37→	BySeverity   map[string]int
 38→}
 39→
 40→// ConsolidatedFinding highlights a finding type shared across clusters.
 41→type ConsolidatedFinding struct {
 42→	Type           string
 43→	Severity       string
 44→	Clusters       []string
 45→	Count          int
 46→	Representative Finding
 47→}
 48→
 49→var severityRanks = map[string]int{
 50→	"low":      1,
 51→	"medium":   2,
 52→	"high":     3,
 53→	"critical": 4,
 54→}
 55→
 56→type clusterAccumulator struct {
 57→	hosts        map[string]struct{}
 58→	findingCount int
 59→	bySeverity   map[string]int
 60→	seenHashes   map[string]struct{}
 61→}
 62→
 63→type consolidatedAccumulator struct {
 64→	count          int
 65→	clusters       map[string]struct{}
 66→	representative Finding
 67→}
 68→
 69→// Aggregate rolls host-level observations into cluster and cross-cluster views.
 70→func Aggregate(observations []ClusterObservation) *AggregateResult {
 71→	result := &AggregateResult{
 72→		Clusters:     []ClusterSummary{},
 73→		CrossCluster: []ConsolidatedFinding{},
 74→		BySeverity:   map[string]int{},
 75→		ByType:       map[string]int{},
 76→	}
 77→	if len(observations) == 0 {
 78→		return result
 79→	}
 80→
 81→	clusterStates := map[string]*clusterAccumulator{}
 82→	crossClusterStates := map[string]*consolidatedAccumulator{}
 83→
 84→	for _, observation := range observations {
 85→		clusterName := strings.TrimSpace(observation.ClusterName)
 86→		clusterState := clusterStates[clusterName]
 87→		if clusterState == nil {
 88→			clusterState = &clusterAccumulator{
 89→				hosts:      map[string]struct{}{},
 90→				bySeverity: map[string]int{},
 91→				seenHashes: map[string]struct{}{},
 92→			}
 93→			clusterStates[clusterName] = clusterState
 94→		}
 95→
 96→		host := strings.TrimSpace(observation.Host)
 97→		if host != "" {
 98→			clusterState.hosts[host] = struct{}{}
 99→		}
100→
101→		for _, rawFinding := range observation.Findings {
102→			finding := normalizeFinding(rawFinding)
103→			if finding.Hash != "" {
104→				if _, seen := clusterState.seenHashes[finding.Hash]; seen {
105→					continue
106→				}
107→				clusterState.seenHashes[finding.Hash] = struct{}{}
108→			}
109→
110→			clusterState.findingCount++
111→			result.TotalFindings++
112→
113→			if finding.Severity != "" {
114→				clusterState.bySeverity[finding.Severity]++
115→				result.BySeverity[finding.Severity]++
116→			}
117→			if finding.Type != "" {
118→				result.ByType[finding.Type]++
119→
120→				crossClusterState := crossClusterStates[finding.Type]
121→				if crossClusterState == nil {
122→					crossClusterState = &consolidatedAccumulator{
123→						clusters:       map[string]struct{}{},
124→						representative: finding,
125→					}
126→					crossClusterStates[finding.Type] = crossClusterState
127→				}
128→				crossClusterState.count++
129→				crossClusterState.clusters[clusterName] = struct{}{}
130→				if shouldReplaceRepresentative(finding, crossClusterState.representative) {
131→					crossClusterState.representative = finding
132→				}
133→			}
134→		}
135→	}
136→
137→	clusterNames := make([]string, 0, len(clusterStates))
138→	for name := range clusterStates {
139→		clusterNames = append(clusterNames, name)
140→	}
141→	sort.Strings(clusterNames)
142→
143→	for _, name := range clusterNames {
144→		clusterState := clusterStates[name]
145→		result.Clusters = append(result.Clusters, ClusterSummary{
146→			Name:         name,
147→			HostCount:    len(clusterState.hosts),
148→			FindingCount: clusterState.findingCount,
149→			BySeverity:   cloneCounts(clusterState.bySeverity),
150→		})
151→	}
152→
153→	crossTypes := make([]string, 0, len(crossClusterStates))
154→	for findingType, state := range crossClusterStates {
155→		if len(state.clusters) < 2 {
156→			continue
157→		}
158→		crossTypes = append(crossTypes, findingType)
159→	}
160→	sort.Strings(crossTypes)
161→
162→	for _, findingType := range crossTypes {
163→		state := crossClusterStates[findingType]
164→		clusters := make([]string, 0, len(state.clusters))
165→		for clusterName := range state.clusters {
166→			clusters = append(clusters, clusterName)
167→		}
168→		sort.Strings(clusters)
169→
170→		result.CrossCluster = append(result.CrossCluster, ConsolidatedFinding{
171→			Type:           findingType,
172→			Severity:       state.representative.Severity,
173→			Clusters:       clusters,
174→			Count:          state.count,
175→			Representative: state.representative,
176→		})
177→	}
178→
179→	return result
180→}
181→
182→func normalizeFinding(f Finding) Finding {
183→	return Finding{
184→		Type:     normalizeKey(f.Type),
185→		Severity: normalizeKey(f.Severity),
186→		Detail:   strings.TrimSpace(f.Detail),
187→		Hash:     strings.TrimSpace(f.Hash),
188→	}
189→}
190→
191→func normalizeKey(value string) string {
192→	return strings.ToLower(strings.TrimSpace(value))
193→}
194→
195→func cloneCounts(counts map[string]int) map[string]int {
196→	cloned := make(map[string]int, len(counts))
197→	for key, value := range counts {
198→		cloned[key] = value
199→	}
200→	return cloned
201→}
202→
203→func shouldReplaceRepresentative(candidate, current Finding) bool {
204→	candidateRank := severityRank(candidate.Severity)
205→	currentRank := severityRank(current.Severity)
206→	if candidateRank != currentRank {
207→		return candidateRank > currentRank
208→	}
209→
210→	if candidate.Detail != current.Detail {
211→		return candidate.Detail < current.Detail
212→	}
213→	if candidate.Hash != current.Hash {
214→		return candidate.Hash < current.Hash
215→	}
216→	if candidate.Severity != current.Severity {
217→		return candidate.Severity < current.Severity
218→	}
219→
220→	return false
221→}
222→
223→func severityRank(severity string) int {
224→	return severityRanks[severity]
225→}
