 14→
 15→// FindingStatus is the lifecycle state for a deduplicated finding hash.
 16→type FindingStatus string
 17→
 18→const (
 19→	// FindingStatusOpen means the finding currently has an active WO.
 20→	FindingStatusOpen FindingStatus = "open"
 21→	// FindingStatusClosed means the finding was resolved/closed.
 22→	FindingStatusClosed FindingStatus = "closed"
 23→)
 24→
 25→// FindingDedupAction describes how the dedup engine handled a finding.
 26→type FindingDedupAction string
 27→
 28→const (
 29→	// FindingDedupActionCreate means the finding hash was new and WO should be created.
 30→	FindingDedupActionCreate FindingDedupAction = "create"
 31→	// FindingDedupActionSuppress means finding was suppressed by dedup rules.
 32→	FindingDedupActionSuppress FindingDedupAction = "suppress"
 33→	// FindingDedupActionReopen means a previously closed finding recurred and should be reopened.
 34→	FindingDedupActionReopen FindingDedupAction = "reopen"
 35→)
 36→
 37→// FindingDedupReason explains why the action was chosen.
 38→type FindingDedupReason string
 39→
 40→const (
 41→	// FindingDedupReasonNewHash indicates a brand-new finding hash.
 42→	FindingDedupReasonNewHash FindingDedupReason = "new_hash"
 43→	// FindingDedupReasonOpenWO indicates suppression due to existing open WO.
 44→	FindingDedupReasonOpenWO FindingDedupReason = "open_wo"
 45→	// FindingDedupReasonDedupWindow indicates suppression due to recurrence inside dedup window.
 46→	FindingDedupReasonDedupWindow FindingDedupReason = "dedup_window"
 47→	// FindingDedupReasonRecurring indicates a closed finding recurred outside dedup window.
 48→	FindingDedupReasonRecurring FindingDedupReason = "recurring"
 49→)
 50→
 51→// FindingHashRecord stores dedup state for a finding hash.
 52→type FindingHashRecord struct {
 53→	Hash      string
 54→	FirstSeen time.Time
 55→	LastSeen  time.Time
 56→	WOID      string
 57→	Status    FindingStatus
 58→}
 59→
 60→// FindingDedupDecision captures dedup action and resulting state.
 61→type FindingDedupDecision struct {
 62→	Action FindingDedupAction
 63→	Reason FindingDedupReason
 64→	Record FindingHashRecord
 65→}
 66→
 67→// ComputeFindingHash returns stable content hash for finding_type + scope + key_attributes.
 68→func ComputeFindingHash(findingType, scope string, keyAttributes map[string]any) (string, error) {
 69→	normalizedType := strings.ToLower(strings.TrimSpace(findingType))
 70→	if normalizedType == "" {
 71→		return "", fmt.Errorf("finding type is required")
 72→	}
 73→	normalizedScope := strings.TrimSpace(scope)
 74→	if normalizedScope == "" {
 75→		return "", fmt.Errorf("scope is required")
 76→	}
 77→	if keyAttributes == nil {
 78→		keyAttributes = map[string]any{}
 79→	}
 80→
 81→	payload := struct {
 82→		FindingType   string         `json:"finding_type"`
 83→		Scope         string         `json:"scope"`
 84→		KeyAttributes map[string]any `json:"key_attributes"`
 85→	}{
 86→		FindingType:   normalizedType,
 87→		Scope:         normalizedScope,
 88→		KeyAttributes: keyAttributes,
 89→	}
 90→	data, err := json.Marshal(payload)
 91→	if err != nil {
 92→		return "", fmt.Errorf("marshal finding hash payload: %w", err)
 93→	}
 94→
 95→	sum := sha256.Sum256(data)
 96→	return hex.EncodeToString(sum[:]), nil
 97→}
 98→
 99→// ComputeObservationHash builds finding hash from observation data.
100→func ComputeObservationHash(scope string, observation wo.Observation) (string, error) {
101→	keyAttributes := make(map[string]any, len(observation.Data)+1)
102→	for k, v := range observation.Data {
103→		keyAttributes[k] = v
104→	}
105→
106→	// Detail is used as a fallback key attribute when classifier did not provide structured data.
107→	if len(keyAttributes) == 0 {
108→		if detail := strings.TrimSpace(observation.Detail); detail != "" {
109→			keyAttributes["detail"] = detail
110→		}
111→	}
112→
113→	return ComputeFindingHash(string(observation.Type), scope, keyAttributes)
114→}
115→
116→// ApplyFindingDedup evaluates and updates finding hash lifecycle state.
117→func ApplyFindingDedup(
118→	cachePath string,
119→	findingHash string,
120→	woID string,
121→	now time.Time,
122→	dedupWindow time.Duration,
123→) (*FindingDedupDecision, error) {
124→	normalizedHash := strings.TrimSpace(findingHash)
125→	if normalizedHash == "" {
126→		return nil, fmt.Errorf("finding hash is required")
127→	}
128→	if now.IsZero() {
129→		now = time.Now().UTC()
130→	} else {
131→		now = now.UTC()
132→	}
133→	if dedupWindow < 0 {
134→		dedupWindow = 0
135→	}
136→
137→	db, err := openCacheDB(cachePath, true)
138→	if err != nil {
139→		return nil, err
140→	}
141→	defer func() {
142→		_ = db.Close()
143→	}()
144→
145→	tx, err := db.Begin()
146→	if err != nil {
147→		return nil, fmt.Errorf("begin finding dedup tx: %w", err)
148→	}
149→	committed := false
150→	defer func() {
151→		if !committed {
152→			_ = tx.Rollback()
153→		}
154→	}()
155→
156→	record, err := readFindingHashTx(tx, normalizedHash)
157→	if err != nil {
158→		return nil, err
159→	}
160→	if record == nil {
161→		newRecord := FindingHashRecord{
162→			Hash:      normalizedHash,
163→			FirstSeen: now,
164→			LastSeen:  now,
165→			WOID:      strings.TrimSpace(woID),
166→			Status:    FindingStatusOpen,
167→		}
168→		if _, err := tx.Exec(`
169→			INSERT INTO finding_hashes (hash, first_seen, last_seen, wo_id, status)
170→			VALUES (?, ?, ?, ?, ?)
171→		`,
172→			newRecord.Hash,
173→			newRecord.FirstSeen.UnixNano(),
174→			newRecord.LastSeen.UnixNano(),
175→			newRecord.WOID,
176→			string(newRecord.Status),
177→		); err != nil {
178→			return nil, fmt.Errorf("insert finding hash %q: %w", normalizedHash, err)
179→		}
180→		if err := tx.Commit(); err != nil {
181→			return nil, fmt.Errorf("commit finding dedup tx: %w", err)
182→		}
183→		committed = true
184→		return &FindingDedupDecision{
185→			Action: FindingDedupActionCreate,
186→			Reason: FindingDedupReasonNewHash,
187→			Record: newRecord,
188→		}, nil
189→	}
190→
191→	record.WOID = strings.TrimSpace(record.WOID)
192→	if record.WOID == "" {
193→		record.WOID = strings.TrimSpace(woID)
194→	}
195→	record.Status = normalizeFindingStatus(record.Status)
196→
197→	if record.Status == FindingStatusOpen {
198→		record.LastSeen = now
199→		if _, err := tx.Exec(`
200→			UPDATE finding_hashes
201→			SET last_seen = ?, wo_id = ?, status = ?
202→			WHERE hash = ?
203→		`,
204→			record.LastSeen.UnixNano(),
205→			record.WOID,
206→			string(FindingStatusOpen),
207→			record.Hash,
208→		); err != nil {
209→			return nil, fmt.Errorf("update open finding hash %q: %w", normalizedHash, err)
210→		}
211→		if err := tx.Commit(); err != nil {
212→			return nil, fmt.Errorf("commit finding dedup tx: %w", err)
213→		}
214→		committed = true
215→		return &FindingDedupDecision{
216→			Action: FindingDedupActionSuppress,
217→			Reason: FindingDedupReasonOpenWO,
218→			Record: *record,
219→		}, nil
220→	}
221→
222→	if dedupWindow > 0 && now.Sub(record.LastSeen) < dedupWindow {
223→		if err := tx.Commit(); err != nil {
224→			return nil, fmt.Errorf("commit finding dedup tx: %w", err)
225→		}
226→		committed = true
227→		return &FindingDedupDecision{
228→			Action: FindingDedupActionSuppress,
229→			Reason: FindingDedupReasonDedupWindow,
230→			Record: *record,
231→		}, nil
232→	}
233→
234→	record.LastSeen = now
235→	record.Status = FindingStatusOpen
236→	if _, err := tx.Exec(`
237→		UPDATE finding_hashes
238→		SET last_seen = ?, wo_id = ?, status = ?
239→		WHERE hash = ?
240→	`,
241→		record.LastSeen.UnixNano(),
242→		record.WOID,
243→		string(record.Status),
244→		record.Hash,
245→	); err != nil {
246→		return nil, fmt.Errorf("reopen finding hash %q: %w", normalizedHash, err)
247→	}
248→	if err := tx.Commit(); err != nil {
249→		return nil, fmt.Errorf("commit finding dedup tx: %w", err)
250→	}
251→	committed = true
252→	return &FindingDedupDecision{
253→		Action: FindingDedupActionReopen,
254→		Reason: FindingDedupReasonRecurring,
255→		Record: *record,
256→	}, nil
257→}
258→
259→// ReadFindingHash returns finding hash state record or nil when missing.
260→func ReadFindingHash(cachePath, findingHash string) (*FindingHashRecord, error) {
261→	normalizedHash := strings.TrimSpace(findingHash)
262→	if normalizedHash == "" {
263→		return nil, fmt.Errorf("finding hash is required")
264→	}
265→
266→	db, err := openCacheDB(cachePath, false)
267→	if err != nil {
268→		return nil, err
269→	}
270→	if db == nil {
271→		return nil, nil
272→	}
273→	defer func() {
274→		_ = db.Close()
275→	}()
276→
277→	row := db.QueryRow(`
278→		SELECT hash, first_seen, last_seen, wo_id, status
279→		FROM finding_hashes
280→		WHERE hash = ?
281→	`, normalizedHash)
282→	return scanFindingHashRow(row)
283→}
284→
285→// UpdateFindingHashStatus updates finding hash lifecycle status.
286→func UpdateFindingHashStatus(cachePath, findingHash string, status FindingStatus, at time.Time) error {
287→	normalizedHash := strings.TrimSpace(findingHash)
288→	if normalizedHash == "" {
289→		return fmt.Errorf("finding hash is required")
290→	}
291→	if !isValidFindingStatus(status) {
292→		return fmt.Errorf("invalid finding status %q", status)
293→	}
294→	if at.IsZero() {
295→		at = time.Now().UTC()
296→	} else {
297→		at = at.UTC()
298→	}
299→
300→	db, err := openCacheDB(cachePath, true)
301→	if err != nil {
302→		return err
303→	}
304→	defer func() {
305→		_ = db.Close()
306→	}()
307→
308→	result, err := db.Exec(`
309→		UPDATE finding_hashes
310→		SET status = ?, last_seen = ?
311→		WHERE hash = ?
312→	`, string(status), at.UnixNano(), normalizedHash)
313→	if err != nil {
314→		return fmt.Errorf("update finding hash status %q: %w", normalizedHash, err)
315→	}
316→
317→	affected, err := result.RowsAffected()
318→	if err != nil {
319→		return fmt.Errorf("rows affected for finding hash %q: %w", normalizedHash, err)
320→	}
321→	if affected == 0 {
322→		return fmt.Errorf("finding hash %q not found", normalizedHash)
323→	}
324→	return nil
325→}
326→
327→func readFindingHashTx(tx *sql.Tx, findingHash string) (*FindingHashRecord, error) {
328→	row := tx.QueryRow(`
329→		SELECT hash, first_seen, last_seen, wo_id, status
330→		FROM finding_hashes
331→		WHERE hash = ?
332→	`, findingHash)
333→	return scanFindingHashRow(row)
334→}
335→
336→type sqlRow interface {
337→	Scan(dest ...any) error
338→}
339→
340→func scanFindingHashRow(row sqlRow) (*FindingHashRecord, error) {
341→	var (
342→		record    FindingHashRecord
343→		firstSeen int64
344→		lastSeen  int64
345→		statusRaw string
346→	)
347→	err := row.Scan(&record.Hash, &firstSeen, &lastSeen, &record.WOID, &statusRaw)
348→	if err != nil {
349→		if err == sql.ErrNoRows {
350→			return nil, nil
351→		}
352→		return nil, fmt.Errorf("scan finding hash row: %w", err)
353→	}
354→
355→	record.FirstSeen = time.Unix(0, firstSeen).UTC()
356→	record.LastSeen = time.Unix(0, lastSeen).UTC()
357→	record.Status = normalizeFindingStatus(FindingStatus(statusRaw))
358→	return &record, nil
359→}
360→
361→func normalizeFindingStatus(status FindingStatus) FindingStatus {
362→	switch FindingStatus(strings.ToLower(strings.TrimSpace(string(status)))) {
363→	case FindingStatusClosed:
364→		return FindingStatusClosed
365→	default:
366→		return FindingStatusOpen
367→	}
368→}
369→
370→func isValidFindingStatus(status FindingStatus) bool {
371→	switch status {
372→	case FindingStatusOpen, FindingStatusClosed:
373→		return true
374→	default:
375→		return false
376→	}
377→}
